}

enum APIError: Error, LocalizedError {
    case invalidURL
    case networkError(Error)
    case decodingError(Error)
    case invalidResponse(statusCode: Int)

    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "The URL is invalid."
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .decodingError(let error):
            return "Failed to decode response: \(error.localizedDescription)"
        case .invalidResponse(let code):
            return "Invalid response with status code \(code)."
        }
    }
}

func fetchUsers(from urlString: String) async throws -> [User] {
    guard let url = URL(string: urlString) else {
        throw APIError.invalidURL
    }
    let (data, response) = try await URLSession.shared.data(from: url)
    guard let httpResponse = response as? HTTPURLResponse else {
        throw APIError.invalidResponse(statusCode: -1)
    }
    guard (200...299).contains(httpResponse.statusCode) else {
        throw APIError.invalidResponse(statusCode: httpResponse.statusCode)
    }
    do {
        return try JSONDecoder().decode([User].self, from: data)
    } catch {
        throw APIError.decodingError(error)
    }
}

enum Result<Value, Error: Swift.Error> {
    case success(Value)
    case failure(Error)

    var value: Value? {
        switch self {
        case .success(let value):
            return value
        case .failure:
            return nil
        }
    }

    var error: Error? {
        switch self {
        case .success:
            return nil
        case .failure(let error):
            return error
        }
    }

    func map<NewValue>(_ transform: (Value) -> NewValue) -> Result<NewValue, Error> {
        switch self {
        case .success(let value):
            return .success(transform(value))
        case .failure(let error):
            return .failure(error)
        }
    }

    func flatMap<NewValue>(_ transform: (Value) -> Result<NewValue, Error>) -> Result<NewValue, Error> {
        switch self {
        case .success(let value):
            return transform(value)
        case .failure(let error):
            return .failure(error)
        }
    }
}

