protocol IdentifiableEntity {
    var id: UUID { get }
    var createdAt: Date { get }
    var updatedAt: Date { get set }
}

extension IdentifiableEntity {
    var isRecentlyCreated: Bool {
        Date().timeIntervalSince(createdAt) < 300
    }

    var ageInSeconds: TimeInterval {
        Date().timeIntervalSince(createdAt)
    }

    mutating func touch() {
        updatedAt = Date()
    }
