enum HTTPMethod: String, Codable {
    case get = "GET"
    case post = "POST"
    case put = "PUT"
    case patch = "PATCH"
    case delete = "DELETE"
}

enum APIResponse<T: Codable>: Codable {
    case success(T)
    case error(message: String, code: Int)

    private enum CodingKeys: String, CodingKey {
        case status
        case data
        case message
        case code
    }

    private enum Status: String, Codable {
        case success
        case error
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let status = try container.decode(Status.self, forKey: .status)
        switch status {
        case .success:
            let data = try container.decode(T.self, forKey: .data)
            self = .success(data)
        case .error:
            let message = try container.decode(String.self, forKey: .message)
            let code = try container.decode(Int.self, forKey: .code)
            self = .error(message: message, code: code)
        }
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .success(let data):
            try container.encode(Status.success, forKey: .status)
            try container.encode(data, forKey: .data)
        case .error(let message, let code):
            try container.encode(Status.error, forKey: .status)
            try container.encode(message, forKey: .message)
            try container.encode(code, forKey: .code)
        }
    }
}

struct Stack<Element> {
    private var storage: [Element] = []

    var isEmpty: Bool { storage.isEmpty }
    var count: Int { storage.count }
    var peek: Element? { storage.last }

    mutating func push(_ element: Element) {
        storage.append(element)
    }

    @discardableResult
    mutating func pop() -> Element? {
        storage.popLast()
    }

    mutating func removeAll() {
        storage.removeAll()
    }
}

extension Stack: ExpressibleByArrayLiteral {
    init(arrayLiteral elements: Element...) {
        storage = elements
    }
}

extension Stack: CustomStringConvertible {
    var description: String {
        "Stack(\(storage.reversed().map { String(describing: $0) }.joined(separator: ", ")))"
    }
}

extension Stack: Sequence {
    func makeIterator() -> IndexingIterator<[Element]> {
        storage.makeIterator()
    }
}

